insert into public.applications (id, kakao_id, name, session, dept, phone, message, avatar_source, status, slot_id, notified, notified_at, applied_at, updated_at) values ('b70b19c8-f5b9-4388-a35e-cd0ac8e58b6b', 'doyoon_k', '김도윤', ARRAY['보컬']::text[], '경영학과 21', '010-2345-6789', '무대에서 노래할 때가 가장 행복합니다. 인디록부터 발라드까지 폭넓게 소화할 수 있어요. 꼭 함께하고 싶습니다.', 'kakao', 'new', NULL, false, NULL, '2026-09-10 21:14:00', '2026-09-10 21:14:00');
insert into public.applications (id, kakao_id, name, session, dept, phone, message, avatar_source, status, slot_id, notified, notified_at, applied_at, updated_at) values ('79f7eba9-ed30-4a35-af15-397bfed0493f', 'seojin.lee', '이서진', ARRAY['기타','베이스']::text[], '컴퓨터공학과 22', '010-3456-7890', '펀크록과 모던록을 좋아합니다. 리듬·리드 기타 모두 가능하고 베이스도 칠 수 있어요. 합주라면 자신 있습니다!', 'kakao', 'interview', 'c7df9b2a-7eef-4f1b-a968-7ec484099a7c', false, NULL, '2026-09-11 14:02:00', '2026-09-11 14:02:00');
insert into public.applications (id, kakao_id, name, session, dept, phone, message, avatar_source, status, slot_id, notified, notified_at, applied_at, updated_at) values ('0a2e3d6a-6011-49cc-a6b6-5f6f22660574', 'haneul_drum', '박하늘', ARRAY['드럼']::text[], '실용음악과 21', '010-4567-8901', '드럼 하나는 정말 자신 있습니다. 정기공연 무대에 꼭 서고 싶어서 지원했어요.', 'kakao', 'pass', '3cc0127d-7ef2-4f16-a19d-d54a2740be67', true, '2026-09-13 11:20:00', '2026-09-09 19:30:00', '2026-09-13 11:20:00');
insert into public.applications (id, kakao_id, name, session, dept, phone, message, avatar_source, status, slot_id, notified, notified_at, applied_at, updated_at) values ('bfba984a-1162-48d4-adc0-385aa141c00a', 'yuna_c', '최유나', ARRAY['건반','보컬']::text[], '영어영문학과 23', '010-5678-9012', '클래식 피아노를 오래 쳤고 밴드 건반에 도전해보고 싶습니다. 코러스도 가능해요!', 'kakao', 'new', NULL, false, NULL, '2026-09-11 22:48:00', '2026-09-11 22:48:00');
insert into public.applications (id, kakao_id, name, session, dept, phone, message, avatar_source, status, slot_id, notified, notified_at, applied_at, updated_at) values ('ff7843da-4a00-4148-aac3-db21d1052960', 'minho_j', '정민호', ARRAY['기타']::text[], '기계공학과 20', '010-6789-0123', '실력은 아직 부족하지만 열정만큼은 누구에게도 지지 않습니다. 열심히 배우겠습니다.', 'kakao', 'fail', NULL, false, NULL, '2026-09-08 16:10:00', '2026-09-08 16:10:00');
