insert into public.recruitment_settings (is_open, semester, headline, body, sessions, period_start, period_end, closed_note, updated_by, updated_at) values (true, '2026-2학기 신입 모집', '보컬 · 건반 세션 우대', '카카오 로그인 후 지원서를 작성하면 면접 일정을 안내드립니다.', ARRAY['보컬','건반']::text[], '2026-08-25', '2026-09-12', '이번 학기 신입 부원 모집은 마감되었습니다. 다음 모집 일정은 공지를 통해 안내드릴게요.', '94ec4e08-13e4-48d2-a7c7-d0d20e739961', '2026-06-10 14:22:00');
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('ed198a8e-8fb1-4ca9-afe7-8da0ac1b8682', 'admin', '공연', true, '94ec4e08-13e4-48d2-a7c7-d0d20e739961', '2026 정기공연 〈청림, 소리내다〉 라인업 확정', '9월 정기공연 〈청림, 소리내다〉 무대에 오를 6개 팀이 최종 확정되었습니다.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('f783c295-4411-4ab5-a5df-99643816ac36', 'admin', '합주실', true, '94ec4e08-13e4-48d2-a7c7-d0d20e739961', '합주실 예약 규칙 변경 안내 (2시간 단위)', '합주실 예약 단위가 기존 1시간에서 2시간으로 변경됩니다. 짧은 예약이 반복되며 전환 시간 낭비가 커진다는 의견을 반영했습니다.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('23bdf931-5c59-4fc3-a9ef-24b41cd0a453', 'admin', '공연', false, '94ec4e08-13e4-48d2-a7c7-d0d20e739961', '9월 정기공연 준비 일정 및 대관 계획', '정기공연까지의 전체 준비 일정을 공유합니다.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('a8575778-e1b2-4e57-a859-0bfed0995104', 'admin', '회계', false, '8c00c7b5-ce8e-4f51-ad35-5643e0f0fe0d', '상반기 회비(3만원) 납부 안내', '상반기 회비 납부 안내드립니다.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('77e2acaf-b0a4-49ab-ab2a-0e0b3834c2e4', 'admin', '합주실', false, '94ec4e08-13e4-48d2-a7c7-d0d20e739961', '합주실 장비 점검 — 6월 18일 오전 사용 불가', '앰프 및 드럼 정기 점검으로 아래 시간 합주실 사용이 제한됩니다.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('d22a061b-12a7-4978-a831-5ea285141d09', 'admin', '회계', false, '8c00c7b5-ce8e-4f51-ad35-5643e0f0fe0d', '4월 회계 내역 공개', '4월 한 달간의 수입·지출 내역을 공개합니다.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('628c3fe1-ce07-4596-a18f-0726add8d4be', 'user', '모집', true, '5a77a124-3403-43e6-a150-dcc248b65fbd', '록 밴드 같이 하실 분! 드럼 급구합니다 🥁', '9월 공연 목표로 록 밴드 팀 꾸리고 있어요. 현재 기타(저)·베이스·보컬 모였고 드럼만 구하면 바로 시작합니다!
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('45b52fa9-d1c6-4ef6-a976-dc95e1dc9261', 'user', '모집', false, 'f1dfb42e-be13-4f37-af73-fdfc2f9dbb85', '보컬+기타 어쿠스틱 듀오 하실 분 찾아요', '잔잔한 어쿠스틱 듀오 같이 하실 기타 세션 구해요. 버스킹이나 소규모 무대 위주로 가볍게 시작해보고 싶어요.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('e1646b0d-b4e4-4afc-a4c4-bcbf8c12ff4c', 'user', '자유', false, 'f65b761d-f85b-4c13-aa0b-0e035d77f723', '이펙터 공동구매 하실 분 (마감 임박)', '멀티 이펙터 공동구매 모집합니다. 5명 이상이면 배송비 무료에 추가 할인까지 가능해요.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('892a941c-fe5f-4182-af57-3ad96a9d92b6', 'user', '행사', false, '959536c5-c590-45ea-ac41-218d600057d0', '여름 MT 〈리프〉 같이 가요 — 사전 수요 조사', '7월 셋째 주 1박 2일 MT 어떠세요? 펜션 잡아서 합주하고 바베큐하고 놀다 오는 컨셉이에요.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('f53fafc1-afd1-4813-a432-871eef9195d3', 'user', '자유', false, '8a15cfc4-e30d-4e04-ac7b-279139d5c4f3', '오늘 합주 끝나고 뒷풀이 하실 분~', '오늘 저녁 합주 마치고 근처에서 가볍게 한잔 어떠세요? 합주실 앞에서 9시쯤 모일 생각이에요.
insert into public.notices (id, kind, tag, pinned, author_id, title, body, rich, views, created_at, updated_at) values ('5c2724db-713b-4d14-af34-c46f39d9243b', 'user', '후기', false, 'f1dfb42e-be13-4f37-af73-fdfc2f9dbb85', '버스킹 〈봄밤〉 후기 + 사진 공유합니다', '지난 주말 교내 버스킹에 함께해 주신 모든 분들 너무 고생 많으셨어요!
