insert into public.references_info (id, icon, label, value, secret, note, ord) values ('a2edb38d-dbc0-4048-a6bf-b268aeb09fe5', 'book', '동아리방 운영 수칙', '08:00 – 24:00', false, '마지막 사용자가 소등·문단속. 음식물 반입 금지, 개인 짐은 사물함만 사용.', 1);
insert into public.references_info (id, icon, label, value, secret, note, ord) values ('b7b84452-620b-462c-a26a-39a6f5f02753', 'guitar', '장비 사용 수칙', '사용 후 원위치', false, '앰프 볼륨 6 이하, 드럼 스틱 개인 지참, 케이블은 8자 정리. 고장 시 즉시 운영진에 보고.', 2);
insert into public.reports (id, category, title, body, anonymous, reporter_id, status, reply, reply_author_id, reply_at, created_at, updated_at) values ('77a09cab-9504-409c-ae71-5f3f0c39c979', 'gear', '합주실 A 기타 앰프 잡음', '주말 합주 때 앰프에서 지지직 잡음이 계속 났어요. 케이블을 바꿔도 동일합니다. 점검 부탁드려요.', false, '8a15cfc4-e30d-4e04-ac7b-279139d5c4f3', 'resolved', '확인해보니 앰프 인풋 잭 접촉 불량이었어요. 6월 11일에 잭을 교체하고 테스트까지 마쳤습니다. 같은 증상이 다시 생기면 바로 알려주세요. 제보 감사합니다!', '94ec4e08-13e4-48d2-a7c7-d0d20e739961', '2026-06-11 13:20:00', '2026-06-10 21:14:00', '2026-06-11 13:20:00');
insert into public.reports (id, category, title, body, anonymous, reporter_id, status, reply, reply_author_id, reply_at, created_at, updated_at) values ('f8e08ed5-1bce-419c-ac6c-67f4fa1a612a', 'noshow', '금요일 저녁 예약 노쇼 반복', '금요일 야간 예약이 비는 경우가 잦아요. 노쇼 패널티를 강화해주시면 좋겠습니다.', true, '8a15cfc4-e30d-4e04-ac7b-279139d5c4f3', 'reviewing', NULL, NULL, NULL, '2026-06-04 10:02:00', '2026-06-04 10:02:00');
insert into public.reports (id, category, title, body, anonymous, reporter_id, status, reply, reply_author_id, reply_at, created_at, updated_at) values ('89deeca6-9546-4167-a8ce-022c6537ed10', 'conduct', '합주 중 고성·다툼', '특정 팀 합주 중 큰 소리로 다투는 일이 있었습니다. 확인 부탁드려요.', true, 'c3ed48dc-0477-43a0-aac1-6f2b84b57a00', 'received', NULL, NULL, NULL, '2026-06-02 23:40:00', '2026-06-02 23:40:00');
insert into public.reports (id, category, title, body, anonymous, reporter_id, status, reply, reply_author_id, reply_at, created_at, updated_at) values ('9b8501d2-e562-4bb6-af2a-95c06f7c89cf', 'suggest', '사물함 증설 요청', '개인 장비를 보관할 사물함이 부족합니다. 증설을 검토 부탁드립니다.', false, '7fda8e5c-0710-4038-a245-e6f91196b35b', 'resolved', '좋은 제안 감사해요. 학생회 예산으로 사물함 8칸을 추가 신청했고, 6월 말 합주실 B 입구에 설치 예정입니다. 배정 방식은 별도 공지로 안내드릴게요.', 'efe23c13-0424-48fd-ad97-23c4fbbdd475', '2026-06-05 16:40:00', '2026-05-28 14:20:00', '2026-06-05 16:40:00');
insert into public.reports (id, category, title, body, anonymous, reporter_id, status, reply, reply_author_id, reply_at, created_at, updated_at) values ('894762b1-cf3d-4784-a086-7dbf68b8d9b5', 'gear', '드럼 하이햇 스탠드 흔들림', '하이햇 스탠드 나사가 헐거워 합주 중 자꾸 흔들립니다.', false, '5a77a124-3403-43e6-a150-dcc248b65fbd', 'received', NULL, NULL, NULL, '2026-05-22 19:05:00', '2026-05-22 19:05:00');
insert into public.notifications (id, recipient_id, type, title, body, target_screen, target_params, read, created_at) values ('8e7a7f7e-9fc3-4d5b-a946-7a6ba6e9ef28', '8a15cfc4-e30d-4e04-ac7b-279139d5c4f3', 'notice', '새 운영진 공지', '2026 정기공연 〈청림, 소리내다〉 라인업이 확정되었어요.', 'notice-detail', '{"id":"n1"}'::jsonb, false, '2026-06-13 19:30:00');
